3	const PROCESSING_FEE = 5;
4	const FIRST_INSURANCE_SURCHARGE = 0.1;
5	const CURSED_SURCHARGE_RATE = 0.5;
6	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
7	const HIGH_ENCHANTMENT_THRESHOLD = 5;
8	
9	const BASE_PREMIUMS: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	  staff: 80,
13	  potion: 40,
14	  rune: 25,
15	  moonstone: 25,
16	};
17	
18	type Item = { type: string; material?: string; cursed?: boolean; enchantment?: number };
19	type Damage = { itemType: string; amount: number };
20	type Incident = { cause?: string; damages: Damage[] };
21	type Step = {
22	  op: string;
23	  items?: Item[];
24	  policy?: number;
25	  incident?: Incident;
26	};
27	type Customer = { yearsWithMHPCO?: number };
28	type Scenario = { steps: Step[]; customer?: Customer };
29	
30	const INSURANCE_VALUES: Record<string, number> = {
31	  sword: 1000,
32	  amulet: 600,
33	  staff: 800,
34	  potion: 400,
35	  rune: 250,
36	  moonstone: 250,
37	};
38	
39	const DEDUCTIBLE = 100;
40	const CAP_MULTIPLIER = 2;
41	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
42	
43	const insuranceValueForType = (type: string): number =>
44	  INSURANCE_VALUES[type] ?? 0;
45	
46	const sumPolicyInsurance = (items: Item[]): number =>
47	  items.reduce((sum, item) => sum + insuranceValueForType(item.type), 0);
48	
49	const findItemInPolicy = (items: Item[], itemType: string): Item => {
50	  const found = items.find((i) => i.type === itemType);
51	  if (!found) throw new Error(`Item type ${itemType} not in policy`);
52	  return found;
53	};
54	
55	const reimbursementForDamage = (item: Item, amount: number): number => {
56	  const enchantment = item.enchantment ?? 0;
57	  const reimbursed =
58	    enchantment >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD ? amount * 0.5 : amount;
59	  return Math.max(0, reimbursed - DEDUCTIBLE);
60	};
61	
62	type ClaimResult = { payout: number; remainingCap: number };
63	
64	const processClaim = (
65	  step: Step,
66	  policySteps: Map<number, Step>,
67	  remainingCaps: Map<number, number>,
68	): ClaimResult => {
69	  const policyIndex = step.policy as number;
70	  const policyStep = policySteps.get(policyIndex);
71	  if (!policyStep || !policyStep.items) {
72	    throw new Error(`Policy at index ${policyIndex} not found`);
73	  }
74	  const damages = step.incident?.damages ?? [];
75	  const totalReimbursement = damages.reduce((sum, damage) => {
76	    const item = findItemInPolicy(policyStep.items!, damage.itemType);
77	    return sum + reimbursementForDamage(item, damage.amount);
78	  }, 0);
79	  const remainingCap = remainingCaps.get(policyIndex) ?? 0;
80	  const payout = Math.floor(Math.min(totalReimbursement, remainingCap));
81	  const newRemainingCap = remainingCap - payout;
82	  remainingCaps.set(policyIndex, newRemainingCap);
83	  return { payout, remainingCap: newRemainingCap };
84	};
85	
86	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
87	const BLOCK_SIZE = 3;
88	const BLOCK_BASE_PREMIUM = 60;
89	
90	const basePremiumForType = (type: string): number => BASE_PREMIUMS[type] ?? 0;
91	
92	const itemBasePremium = (item: Item): number => basePremiumForType(item.type);
93	
94	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
95	
96	const countByType = (items: Item[]): Map<string, number> => {
97	  const counts = new Map<string, number>();
98	  for (const item of items) {
99	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
100	  }
101	  return counts;
102	};
103	
104	const componentGroupPremium = (type: string, count: number): number =>
105	  count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * basePremiumForType(type);
106	
107	const sumItemBasePremiums = (items: Item[]): number => {
108	  const nonComponents = items.filter((item) => !isComponent(item));
109	  const components = items.filter(isComponent);
110	  const nonComponentsTotal = nonComponents.reduce(
111	    (sum, item) => sum + itemBasePremium(item),
112	    0,
113	  );
114	  const componentsTotal = Array.from(countByType(components)).reduce(
115	    (sum, [type, count]) => sum + componentGroupPremium(type, count),
116	    0,
117	  );
118	  return nonComponentsTotal + componentsTotal;
119	};
120	
121	const isCursed = (item: Item): boolean => item.cursed === true;
122	
123	const isHighlyEnchanted = (item: Item): boolean =>
124	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
125	
126	const cursedSurcharge = (item: Item, base: number): number =>
127	  isCursed(item) ? base * CURSED_SURCHARGE_RATE : 0;
128	
129	const highEnchantmentSurcharge = (item: Item, base: number): number =>
130	  isHighlyEnchanted(item) ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
131	
132	const itemSurcharge = (item: Item): number => {
133	  const base = itemBasePremium(item);
134	  return cursedSurcharge(item, base) + highEnchantmentSurcharge(item, base);
135	};
136	
137	const sumItemSurcharges = (items: Item[]): number =>
138	  items.reduce((sum, item) => sum + itemSurcharge(item), 0);
139	
140	const LOYALTY_DISCOUNT_RATE = 0.2;
141	const LOYALTY_THRESHOLD_YEARS = 2;
142	
143	const isLongStandingCustomer = (customer: Customer | undefined): boolean =>
144	  (customer?.yearsWithMHPCO ?? 0) >= LOYALTY_THRESHOLD_YEARS;
145	
146	const loyaltyDiscountFor = (customer: Customer | undefined, base: number): number =>
147	  isLongStandingCustomer(customer) ? base * LOYALTY_DISCOUNT_RATE : 0;
148	
149	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
150	
151	const followUpDiscountFor = (isFollowUp: boolean, base: number): number =>
152	  isFollowUp ? base * FOLLOW_UP_DISCOUNT_RATE : 0;
153	
154	const quotePremiumFor = (
155	  step: Step,
156	  customer: Customer | undefined,
157	  isFollowUp: boolean,
158	): number => {
159	  const items = step.items ?? [];
160	  const itemsBase = sumItemBasePremiums(items);
161	  const surcharges =
162	    sumItemSurcharges(items) + itemsBase * FIRST_INSURANCE_SURCHARGE;
163	  const discounts =
164	    loyaltyDiscountFor(customer, itemsBase) +
165	    followUpDiscountFor(isFollowUp, itemsBase);
166	  return Math.ceil(itemsBase + surcharges - discounts + PROCESSING_FEE);
167	};
168	
169	const validateItemTypes = (items: Item[]): void => {
170	  for (const item of items) {
171	    if (!(item.type in BASE_PREMIUMS)) {
172	      throw new Error(`Unknown item type: ${item.type}`);
173	    }
174	  }
175	};
176	
177	export function runScenario(scenario: unknown): { results: any[] } {
178	  const s = scenario as Scenario;
179	  const policySteps = new Map<number, Step>();
180	  const remainingCaps = new Map<number, number>();
181	  const results = s.steps.map((step, index) => {
182	    if (step.op === "claim") {
183	      return processClaim(step, policySteps, remainingCaps);
184	    }
185	    const items = step.items ?? [];
186	    validateItemTypes(items);
187	    policySteps.set(index, step);
188	    remainingCaps.set(index, sumPolicyInsurance(items) * CAP_MULTIPLIER);
189	    return { premium: quotePremiumFor(step, s.customer, index > 0) };
190	  });
191	  return { results };
192	}
